import React, { useEffect, useState } from "react";
import { io } from "socket.io-client";
import waveIcon from "../assets/waveAgent.png";
import "./chatBot.css";

const socket = io("http://localhost:3002");

/* ==============================
   STOCK LIST (Stable)
============================== */

const stocks = [
  "SBIN",
  "TATAPOWER",
  "RELIANCE",
  "QUICKHEAL",
  "M&M",
  "TCS",
  "KPITTECH",
  "SGBMAY29",
  "INFY",
  "WIPRO",
  "HUL",
  "BHARTIARTL",
  "ITC",
  "HDFCBANK",
];

const hints = [
  "portfolio summary",
  "risk check",
  ...stocks.map((s) => `buy ${s} 10 1000`),
  ...stocks.map((s) => `sell ${s} 5 1500`),
];

/* ==============================
   COMPONENT
============================== */

const ChatBot = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [isOpen, setIsOpen] = useState(false);
  const [hintIndex, setHintIndex] = useState(0);

  /* ==============================
     ROTATING PLACEHOLDER
  ============================== */

  useEffect(() => {
    const interval = setInterval(() => {
      setHintIndex((prev) => (prev + 1) % hints.length);
    }, 2500);

    return () => clearInterval(interval);
  }, []);

  /* ==============================
     SOCKET LISTENER
  ============================== */

  useEffect(() => {
    socket.on("aiMessage", (msg) => {
      setMessages((prev) => [...prev, { type: "ai", text: msg }]);
    });

    return () => socket.off("aiMessage");
  }, []);

  /* ==============================
     SEND MESSAGE
  ============================== */

  const sendMessage = async () => {
    if (!input.trim()) return;

    const text = input.trim();
    const lower = text.toLowerCase();
    const parts = text.trim().split(/\s+/);

    // BUY COMMAND
    if (lower.startsWith("buy") && parts.length === 4) {
      const [, name, qty, price] = parts;

      try {
        await fetch("http://localhost:3002/newOrder", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name: name.toUpperCase(),
            qty: Number(qty),
            price: Number(price),
            mode: "BUY",
          }),
        });

        setMessages((prev) => [
          ...prev,
          { type: "user", text },
          { type: "ai", text: `✅ Buy order placed for ${name.toUpperCase()}` },
        ]);
      } catch {
        setMessages((prev) => [
          ...prev,
          { type: "ai", text: "❌ Failed to place buy order." },
        ]);
      }

      setInput("");
      return;
    }

    // SELL COMMAND
    if (lower.startsWith("sell") && parts.length === 4) {
      const [, name, qty, price] = parts;

      try {
        await fetch("http://localhost:3002/newOrder", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name: name.toUpperCase(),
            qty: Number(qty),
            price: Number(price),
            mode: "SELL",
          }),
        });

        setMessages((prev) => [
          ...prev,
          { type: "user", text },
          { type: "ai", text: `✅ Sell order placed for ${name.toUpperCase()}` },
        ]);
      } catch {
        setMessages((prev) => [
          ...prev,
          { type: "ai", text: "❌ Failed to place sell order." },
        ]);
      }

      setInput("");
      return;
    }

    // NORMAL CHAT
    socket.emit("userMessage", text);

    setMessages((prev) => [...prev, { type: "user", text }]);
    setInput("");
  };

  return (
    <>
      {!isOpen && (
        <img
          src={waveIcon}
          alt="Wave Agent"
          className="chat-icon-img"
          onClick={() => setIsOpen(true)}
        />
      )}

      {isOpen && (
        <div className="chat-window">
          <div className="chat-window-header">
            <button
              className="back-btn"
              onClick={() => setIsOpen(false)}
            >
              ←
            </button>
            <span className="chat-title">Wave Agent</span>
          </div>

          <div className="chat-body">
            {messages.map((msg, i) => (
              <div key={i} className={`msg ${msg.type}`}>
                {msg.text}
              </div>
            ))}
          </div>

          <div className="chat-input">
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={`Try: ${hints[hintIndex]}`}
              onKeyDown={(e) => e.key === "Enter" && sendMessage()}
            />
            <button onClick={sendMessage}>Send</button>
          </div>
        </div>
      )}
    </>
  );
};

export default ChatBot;
